import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  Send, QrCode, Users, History, Settings, Coins, LogOut, CheckCircle2, 
  AlertCircle, Smartphone, ShieldCheck, LayoutDashboard, ArrowRight, 
  UploadCloud, User, Loader2, Lock, ChevronRight, PlusCircle, CreditCard, 
  Zap, ShoppingBag, Ticket, Image as ImageIcon, Film, X, Database, 
  Activity, Search, Edit, Trash2, MoreVertical, Save, ShieldAlert, 
  TrendingUp, MessageSquare, Server, Plus, Minus, Bell, LogIn, Play, Download,
  RefreshCw, ListPlus, Paperclip
} from 'lucide-react';

const API_URL = 'http://localhost:5000/api';

/* ============================================================================
   CONSTANTS & PRICING
   ============================================================================ */
const TOPUP_PACKAGES = [
  { id: 'tu_1', amount: 500, price: 15, label: 'Lite Reload', icon: Ticket, bonus: null },
  { id: 'tu_2', amount: 1500, price: 40, label: 'Basic Reload', icon: Zap, bonus: '+50 Bonus' },
  { id: 'tu_3', amount: 4000, price: 90, label: 'Pro Reload', icon: Coins, bonus: '+200 Bonus', popular: true },
  { id: 'tu_4', amount: 10000, price: 150, label: 'Enterprise Reload', icon: ShieldCheck, bonus: '+1,000 Bonus' }
];

const QRCodeImage = ({ value, size = 200 }) => {
  const qrUrl = `https://quickchart.io/qr?text=${encodeURIComponent(value)}&size=${size}&margin=1`;
  return (
    <div className="bg-white p-4 rounded-3xl shadow-xl border border-slate-100 inline-block">
      <img src={qrUrl} alt="WhatsApp QR" width={size} height={size} className="rounded-xl" />
    </div>
  );
};

/* ============================================================================
   PORTAL ADMIN (UI MOCK)
   ============================================================================ */
const AdminPortal = ({ currentUser, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 flex w-full">
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col h-screen fixed left-0 top-0">
        <div className="h-20 flex items-center px-6 border-b border-slate-800 bg-slate-950">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-500 p-2 rounded-xl text-white">
              <ShieldAlert size={20} fill="currentColor" />
            </div>
            <div>
              <h1 className="text-white font-black text-lg leading-tight tracking-tight">AR CONNECT</h1>
              <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest">Admin Portal</p>
            </div>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <p className="px-4 text-[10px] font-black uppercase tracking-widest text-slate-600 mb-4 mt-4">Menu Utama</p>
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
            { id: 'users', icon: Users, label: 'User Management' },
            { id: 'settings', icon: Settings, label: 'System Settings' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold transition-all text-sm ${
                activeTab === item.id 
                  ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' 
                  : 'hover:bg-slate-800 hover:text-white'
              }`}
            >
              <item.icon size={18} />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center gap-3 px-4 py-3 mb-2 bg-slate-800 rounded-xl">
            <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-white font-bold">AD</div>
            <div className="flex-1 overflow-hidden">
              <p className="text-xs font-bold text-white truncate">{currentUser.nama_syarikat || 'Admin'}</p>
              <p className="text-[10px] text-slate-400 truncate">System Administrator</p>
            </div>
          </div>
          <button onClick={onLogout} className="w-full flex items-center justify-center gap-2 px-4 py-3 text-sm font-bold text-red-400 hover:bg-red-500/10 rounded-xl transition-all">
            <LogOut size={16} /> Logout
          </button>
        </div>
      </aside>

      <main className="flex-1 ml-64 flex flex-col h-screen overflow-hidden">
        <header className="h-20 bg-white border-b flex items-center justify-between px-8 sticky top-0 z-10">
          <div><h2 className="text-xl font-black text-slate-800 capitalize">{activeTab}</h2></div>
        </header>
        <div className="flex-1 overflow-y-auto p-8 flex items-center justify-center text-slate-400 font-bold">
            Data pengguna sebenar akan disambungkan pada fasa pengurusan admin kelak.
        </div>
      </main>
    </div>
  );
};

/* ============================================================================
   PORTAL PENGGUNA (CLIENT) DENGAN INTEGRASI API SEBENAR
   ============================================================================ */
const UserPortal = ({ currentUser, token, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [credits, setCredits] = useState(currentUser.kredit || 0);

  // WhatsApp States
  const [isDeviceLinked, setIsDeviceLinked] = useState(false);
  const [qrStatus, setQrStatus] = useState('idle'); 
  const [qr, setQr] = useState(null);
  const isRequesting = useRef(false);

  // Blast States
  const [isBlasting, setIsBlasting] = useState(false);
  const [blastProgress, setBlastProgress] = useState(0);
  const [messagesSent, setMessagesSent] = useState(0);
  const [messagesFailed, setMessagesFailed] = useState(0);
  const [message, setMessage] = useState('');
  const [targetSource, setTargetSource] = useState('manual');
  const [manualNumbers, setManualNumbers] = useState('');
  const [selectedGroup, setSelectedGroup] = useState('all');

  // Media States
  const [mediaFile, setMediaFile] = useState(null);

  // Database Contacts States
  const [contacts, setContacts] = useState([]);
  const [newContact, setNewContact] = useState({ nama: '', nombor_telefon: '', kumpulan: 'Umum' });
  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isUploadingCSV, setIsUploadingCSV] = useState(false); 
  const [isDeletingAll, setIsDeletingAll] = useState(false);

  const uniqueGroups = useMemo(() => {
    const groups = new Set(contacts.map(c => c.kumpulan));
    return Array.from(groups);
  }, [contacts]);

  const fetchContacts = async () => {
    try {
      const res = await fetch(`${API_URL}/contacts/${currentUser.id}`);
      if (res.ok) {
        const data = await res.json();
        setContacts(data);
      }
    } catch (err) {
      console.error("Gagal load database", err);
    }
  };

  useEffect(() => {
    fetchContacts();
    // eslint-disable-next-line
  }, [activeTab]);

  const handleAddContact = async (e) => {
    e.preventDefault();
    if (!newContact.nombor_telefon) return;

    setIsAddingContact(true);
    try {
      const res = await fetch(`${API_URL}/contacts`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user_id: currentUser.id, ...newContact })
      });
      if (res.ok) {
        setNewContact({ nama: '', nombor_telefon: '', kumpulan: 'Umum' });
        fetchContacts();
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsAddingContact(false);
    }
  };

  const handleDeleteContact = async (id) => {
    if (!window.confirm("Pasti mahu padam kenalan ini?")) return;
    try {
      const res = await fetch(`${API_URL}/contacts/${id}`, { method: 'DELETE' });
      if (res.ok) fetchContacts();
    } catch (err) {
      console.error(err);
    }
  };

  const handleDeleteAllContacts = async () => {
    if (!window.confirm("AWAS! Adakah anda pasti mahu memadam KESEMUA kenalan? Tindakan ini tidak boleh dikembalikan.")) return;

    setIsDeletingAll(true);
    try {
      await Promise.all(contacts.map(contact => 
        fetch(`${API_URL}/contacts/${contact._id}`, { method: 'DELETE' })
      ));

      alert("Kesemua kenalan telah dipadam bersih!");
      fetchContacts();
    } catch (err) {
      console.error("Gagal memadam semua:", err);
      alert("Berlaku ralat semasa memadam. Sila cuba lagi.");
    } finally {
      setIsDeletingAll(false);
    }
  };

  // --- Fungsi Muat Naik Fail Media ---
  const handleMediaUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    // Hadkan saiz maksimum fail ke 16MB (Standard WhatsApp)
    if (file.size > 16 * 1024 * 1024) {
      alert("Saiz fail media melebihi 16MB. Sila muat naik fail yang lebih kecil.");
      e.target.value = null;
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      setMediaFile({
        file: file,
        type: file.type,
        name: file.name,
        base64: event.target.result // base64 representation of image/video
      });
    };
    reader.readAsDataURL(file);
    e.target.value = null; // reset input
  };

  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setIsUploadingCSV(true);

    try {
      const XLSX = await new Promise((resolve, reject) => {
        if (window.XLSX) return resolve(window.XLSX);
        const script = document.createElement('script');
        script.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
        script.onload = () => resolve(window.XLSX);
        script.onerror = () => reject(new Error('Gagal memuat turun pustaka XLSX'));
        document.head.appendChild(script);
      });

      const reader = new FileReader();

      reader.onload = async (event) => {
        try {
          const data = new Uint8Array(event.target.result);
          const workbook = XLSX.read(data, { type: 'array' });

          const firstSheetName = workbook.SheetNames[0];
          const worksheet = workbook.Sheets[firstSheetName];

          const rows = XLSX.utils.sheet_to_json(worksheet, { header: 1 });
          const newContacts = [];

          for (let i = 0; i < rows.length; i++) {
            const row = rows[i];
            if (!row || row.length === 0) continue;

            let col0 = row[0] !== undefined ? String(row[0]).trim() : '';
            let col1 = row[1] !== undefined ? String(row[1]).trim() : '';
            let col2 = row[2] !== undefined ? String(row[2]).trim() : '';

            if (col0 && !col1 && col0.includes(',')) {
                const splitCols = col0.split(/[,;\t]/);
                col0 = splitCols[0] ? splitCols[0].replace(/"/g, '').trim() : '';
                col1 = splitCols[1] ? splitCols[1].replace(/"/g, '').trim() : '';
                col2 = splitCols[2] ? splitCols[2].replace(/"/g, '').trim() : '';
            }

            let nama = col0;
            let nombor = col1;
            let kumpulan = col2;

            if (!nombor && nama) {
                const possibleNumber = nama.replace(/[^0-9]/g, '');
                if (possibleNumber.length > 8) {
                    nombor = possibleNumber;
                    nama = 'Pelanggan';
                }
            }

            if (i === 0 && (nama.toLowerCase().includes('nama') || (nombor && nombor.toLowerCase().includes('nombor')))) continue;

            const cleanPhone = nombor ? nombor.replace(/[^0-9]/g, '') : '';

            if (!cleanPhone || cleanPhone.length < 8) continue; 

            newContacts.push({
              nama: nama || 'Pelanggan',
              nombor_telefon: cleanPhone,
              kumpulan: kumpulan || 'Import Excel/CSV'
            });
          }

          if (newContacts.length === 0) {
            alert("Tiada data yang sah dijumpai. Pastikan fail mengandungi nombor telefon di lajur yang betul.");
            setIsUploadingCSV(false);
            return;
          }

          const res = await fetch(`${API_URL}/contacts/bulk`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ user_id: currentUser.id, contacts: newContacts })
          });

          if (res.ok) {
            alert(`${newContacts.length} kenalan dari fail berjaya diimport!`);
            fetchContacts(); 
          } else {
            const resData = await res.json();
            alert(`Ralat Server: ${resData.message || 'Gagal memproses fail'}`);
          }
        } catch (err) {
          console.error("Ralat memproses fail", err);
          alert("Gagal memproses fail. Sila pastikan format adalah betul.");
        } finally {
          setIsUploadingCSV(false);
          if (e.target) e.target.value = null; 
        }
      };

      reader.readAsArrayBuffer(file);

    } catch (err) {
      console.error(err);
      alert("Sistem gagal memuat turun pemproses Excel. Pastikan anda mempunyai capaian internet.");
      setIsUploadingCSV(false);
      e.target.value = null;
    }
  };

  const connectWA = async () => {
    setQrStatus('loading');
    setQr(null);
    try {
      const res = await fetch(`${API_URL}/whatsapp/connect/${currentUser.id}`);
      if (!res.ok) throw new Error("Gagal hubungi server");
    } catch (err) {
      console.error(err);
      setQrStatus('error');
    }
  };

  const logoutWA = async () => {
    setQrStatus('disconnecting');
    try {
      await fetch(`${API_URL}/whatsapp/logout`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: currentUser.id })
      });
    } catch (err) {
      console.error("Gagal putuskan sambungan dari server:", err);
    }
    setQrStatus('idle');
    setIsDeviceLinked(false);
    setQr(null);
  };

  useEffect(() => {
    let interval;
    let isMounted = true;

    const checkServerStatus = async () => {
      if (isRequesting.current) return; 
      isRequesting.current = true;

      try {
        const res = await fetch(`${API_URL}/whatsapp/connect/${currentUser.id}`);
        const data = await res.json();
        if (!isMounted) return;

        if (data.status === 'connected' || data.connected) {
          setQrStatus('connected');
          setIsDeviceLinked(true);
          setQr(null);
        } else if (data.status === 'disconnected') { 
          setQrStatus('idle');
          setIsDeviceLinked(false);
          setQr(null);
        } else if (data.qr && qrStatus !== 'connected') {
          setQr(prevQr => prevQr !== data.qr ? data.qr : prevQr);
          setQrStatus('qr_ready');
        }
      } catch (err) {
      } finally {
        isRequesting.current = false;
      }
    };

    if (qrStatus === 'loading' || qrStatus === 'qr_ready') {
      interval = setInterval(checkServerStatus, 1500);
    } else if (qrStatus === 'connected') {
      interval = setInterval(checkServerStatus, 5000);
    }

    return () => {
      isMounted = false;
      if (interval) clearInterval(interval);
    };
  }, [qrStatus, currentUser.id]);

  const startBlast = async () => {
    if (!isDeviceLinked) { 
      alert("Sila hubungkan WhatsApp anda terlebih dahulu!");
      setActiveTab('dashboard'); 
      return; 
    }

    let numbers = [];

    if (targetSource === 'manual') {
      numbers = manualNumbers.split(/[\n,]+/).map(n => n.trim()).filter(n => n.length > 5);
    } else if (targetSource === 'database') {
      const filteredContacts = selectedGroup === 'all' 
        ? contacts 
        : contacts.filter(c => c.kumpulan === selectedGroup);
      numbers = filteredContacts.map(c => c.nombor_telefon);
    }

    if (numbers.length === 0) {
      alert("Sila masukkan/pilih nombor sasaran!");
      return;
    }

    // Periksa sama ada pengguna telah memasukkan teks atau melampirkan media
    if (!message && !mediaFile) {
      alert("Sila masukkan sekurang-kurangnya satu teks atau lampiran gambar/video!");
      return;
    }

    if (credits < numbers.length) {
      alert(`Kredit tidak mencukupi! Anda perlukan ${numbers.length} kredit.`);
      return;
    }

    setIsBlasting(true); 
    setBlastProgress(0); 
    setMessagesSent(0);
    setMessagesFailed(0);

    let successCount = 0;
    let failCount = 0;

    for (let i = 0; i < numbers.length; i++) {
      try {
        const payload = { 
            userId: currentUser.id, 
            to: numbers[i], 
            message: message 
        };

        // Sertakan fail media jika ada
        if (mediaFile) {
            payload.media = mediaFile.base64;
            payload.mediaType = mediaFile.type;
            payload.fileName = mediaFile.name;
        }

        const res = await fetch(`${API_URL}/whatsapp/send`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });

        if (res.ok) {
          successCount++;
          setMessagesSent(successCount);
          setCredits(prev => prev - 1); 
        } else {
          failCount++;
          setMessagesFailed(failCount);
        }
      } catch (err) {
        failCount++;
        setMessagesFailed(failCount);
        console.error(`Gagal menghantar ke ${numbers[i]}`, err);
      }
      setBlastProgress(Math.floor(((i + 1) / numbers.length) * 100));
      await new Promise(resolve => setTimeout(resolve, 2000));
    }

    setTimeout(() => {
      setIsBlasting(false);
      alert(`KEMPEN SELESAI\n\n✅ Berjaya Dihantar: ${successCount}\n❌ Gagal: ${failCount}\n\n*Nota: Nombor yang gagal biasanya tiada akaun WhatsApp aktif atau disekat.`);
    }, 2000);
  };

  const SidebarItem = ({ id, icon: Icon, label }) => (
    <button 
      onClick={() => setActiveTab(id)}
      className={`flex items-center gap-4 w-full p-4 rounded-2xl font-black text-sm transition-all ${activeTab === id ? 'bg-green-500 text-white shadow-lg shadow-green-100' : 'text-slate-400 hover:bg-slate-50 hover:text-slate-600'}`}
    >
      <Icon size={20} /> {label}
    </button>
  );

  return (
    <div className="flex flex-col lg:flex-row h-screen overflow-hidden bg-slate-50 text-slate-800 w-full font-sans">
      <aside className="w-full lg:w-72 bg-white border-r border-slate-100 h-full flex flex-col flex-shrink-0 hidden lg:flex">
        <div className="p-8 flex-grow space-y-6">
          <div className="flex items-center gap-3 mb-10">
            <div className="bg-green-500 p-2 rounded-xl text-white"><Send size={20} fill="currentColor" /></div>
            <span className="text-xl font-black tracking-tight text-slate-900">AR CONNECT</span>
          </div>

          <div className="p-5 bg-slate-900 text-white rounded-[2rem] shadow-xl relative overflow-hidden group">
            <p className="text-[10px] font-black opacity-60 uppercase mb-1 tracking-widest relative z-10">Credit Balance</p>
            <div className="flex items-baseline gap-2 relative z-10">
              <span className="text-3xl font-black">{credits.toLocaleString()}</span>
              <span className="text-xs opacity-50">Units</span>
            </div>
            <button onClick={() => setActiveTab('topup')} className="mt-4 w-full bg-green-500 hover:bg-green-600 text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all relative z-10">
              <PlusCircle size={14} /> Top Up Credits
            </button>
            <Coins className="absolute -right-4 -bottom-4 text-white opacity-5 rotate-12 group-hover:scale-110 transition duration-500" size={100} />
          </div>

          <nav className="space-y-1">
            <SidebarItem id="dashboard" icon={LayoutDashboard} label="Dashboard" />
            <SidebarItem id="blast" icon={Send} label="Fast Blast" />
            <SidebarItem id="contacts" icon={Users} label="Database" />
            <SidebarItem id="topup" icon={ShoppingBag} label="Beli Kredit" />
          </nav>
        </div>
        <div className="p-8 border-t border-slate-100">
          <div className="flex items-center gap-3 mb-6 bg-slate-50 p-3 rounded-2xl">
            <div className="w-10 h-10 bg-white border rounded-xl flex items-center justify-center text-slate-400"><User size={18} /></div>
            <div className="overflow-hidden">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Plan: STANDARD</p>
              <p className="text-xs font-bold truncate text-slate-800">{currentUser.email}</p>
            </div>
          </div>
          <button onClick={onLogout} className="w-full flex items-center justify-center gap-3 p-4 text-red-500 font-black hover:bg-red-50 rounded-2xl transition border border-transparent text-[10px] uppercase tracking-widest">
            <LogOut size={16} /> Logout
          </button>
        </div>
      </aside>

      <main className="flex-grow flex flex-col h-screen overflow-hidden">
        <header className="h-24 bg-white border-b border-slate-100 px-10 flex items-center justify-between flex-shrink-0">
          <div>
            <h2 className="text-xl font-black capitalize">{activeTab === 'contacts' ? 'Database Kenalan' : activeTab}</h2>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Portal Klien / {currentUser.nama_syarikat}</p>
          </div>
          <div className="flex items-center gap-6">
            <div className="flex flex-col text-right">
              <span className="text-sm font-black text-slate-900">{currentUser.nama_syarikat}</span>
              <span className="text-[10px] font-bold text-green-500 uppercase tracking-widest">Lesen Aktif</span>
            </div>
            <div className="w-12 h-12 bg-slate-100 rounded-2xl flex items-center justify-center border-2 border-white shadow-sm overflow-hidden">
              <User className="text-slate-400" />
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10">

          {/* Dashboard Tab */}
          {activeTab === 'dashboard' && (
            <div className="max-w-6xl mx-auto space-y-10">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                  { label: 'Jumlah Hantar', val: '0', color: 'blue', icon: Send },
                  { label: 'Kenalan Database', val: contacts.length.toString(), color: 'green', icon: Users },
